import WidgetKit
import Foundation

struct ExampleProvider: TimelineProvider {
    func placeholder(in context: Context) -> ExampleEntry {
        ExampleEntry(date: Date(), value: 0, label: "Loading...")
    }

    func getSnapshot(in context: Context, completion: @escaping (ExampleEntry) -> Void) {
        let entry = ExampleEntry(date: Date(), value: 42, label: "Snapshot")
        completion(entry)
    }

    func getTimeline(in context: Context, completion: @escaping (Timeline<ExampleEntry>) -> Void) {
        let currentDate = Date()
        let entry = ExampleEntry(date: currentDate, value: 42, label: "Live")
        let nextUpdate = Calendar.current.date(byAdding: .hour, value: 1, to: currentDate)!
        let timeline = Timeline(entries: [entry], policy: .after(nextUpdate))
        completion(timeline)
    }
}

canonicalCode.WidgetExtension/ExampleWidgetView.swift:
import SwiftUI
import WidgetKit

struct ExampleWidgetView: View {
    var entry: ExampleEntry
    @Environment(\.widgetFamily) var family

    var body: some View {
        switch family {
        case .systemSmall:
            VStack {
                Text("\(entry.value)")
                    .font(.largeTitle)
                    .fontWeight(.bold)
                Text(entry.label)
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            .containerBackground(.fill.tertiary, for: .widget)
        default:
            HStack {
                VStack(alignment: .leading) {
                    Text("\(entry.value)")
                        .font(.largeTitle)
                        .fontWeight(.bold)
                    Text(entry.label)
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
                Spacer()
            }
            .padding()
            .containerBackground(.fill.tertiary, for: .widget)
        }
    }
}

